import{_ as t,o as n,c as a,af as o}from"./chunks/framework.BSym9njW.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01-deploy/gemma4/gemma4_model.md","filePath":"en/01-deploy/gemma4/gemma4_model.md","lastUpdated":1778402464000}'),r={name:"01-deploy/gemma4/gemma4_model.md"};function i(l,e,s,d,g,c){return n(),a("div",null,[...e[0]||(e[0]=[o('<h2 id="gemma-4-model-introduction" tabindex="-1">Gemma 4 Model Introduction <a class="header-anchor" href="#gemma-4-model-introduction" aria-label="Permalink to &quot;Gemma 4 Model Introduction&quot;">​</a></h2><p>Gemma 4 is Google DeepMind&#39;s next-generation multimodal open-source model family, built on the same research and technology as Gemini 3, released under the <strong>Apache 2.0</strong> license. It supports text, image, video, and audio inputs, generating text outputs. Gemma 4 is a comprehensive upgrade over previous generations — stronger reasoning capabilities, more flexible multimodal support, more efficient architecture design — while offering multiple sizes from edge devices to servers, specifically designed for advanced reasoning and agentic workflows.</p><p>Since the first Gemma release, developers have collectively downloaded the models over <strong>400 million times</strong>, and the community has built over <strong>100,000</strong> Gemma variants, forming a massive Gemmaverse ecosystem. Gemma 4 is Google&#39;s latest response to community needs — achieving frontier capabilities with parameter efficiency.</p><blockquote><p>References: <a href="https://huggingface.co/blog/gemma4" target="_blank" rel="noreferrer">Hugging Face Blog - Welcome Gemma 4</a> · <a href="https://blog.google/innovation-and-ai/technology/developers-tools/gemma-4/" target="_blank" rel="noreferrer">Google Blog - Gemma 4</a></p></blockquote><hr><h3 id="_1-model-version-overview" tabindex="-1">1. Model Version Overview <a class="header-anchor" href="#_1-model-version-overview" aria-label="Permalink to &quot;1. Model Version Overview&quot;">​</a></h3><p>Gemma 4 comes in four sizes, each with both <strong>base</strong> and <strong>IT (instruction-tuned)</strong> versions:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Model</th><th style="text-align:left;">Parameter Scale</th><th style="text-align:left;">Context Window</th><th style="text-align:left;">Model Links</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Gemma 4 E2B</strong></td><td style="text-align:left;">2.3B effective parameters, 5.1B total with embeddings</td><td style="text-align:left;">128K</td><td style="text-align:left;"><a href="https://huggingface.co/google/gemma-4-E2B" target="_blank" rel="noreferrer">base</a> / <a href="https://huggingface.co/google/gemma-4-E2B-it" target="_blank" rel="noreferrer">IT</a></td></tr><tr><td style="text-align:left;"><strong>Gemma 4 E4B</strong></td><td style="text-align:left;">4.5B effective parameters, 8B total with embeddings</td><td style="text-align:left;">128K</td><td style="text-align:left;"><a href="https://huggingface.co/google/gemma-4-E4B" target="_blank" rel="noreferrer">base</a> / <a href="https://huggingface.co/google/gemma-4-E4B-it" target="_blank" rel="noreferrer">IT</a></td></tr><tr><td style="text-align:left;"><strong>Gemma 4 31B</strong></td><td style="text-align:left;">31B dense model</td><td style="text-align:left;">256K</td><td style="text-align:left;"><a href="https://huggingface.co/google/gemma-4-31B" target="_blank" rel="noreferrer">base</a> / <a href="https://huggingface.co/google/gemma-4-31B-it" target="_blank" rel="noreferrer">IT</a></td></tr><tr><td style="text-align:left;"><strong>Gemma 4 26B A4B</strong></td><td style="text-align:left;">MoE architecture, 4B active / 26B total parameters</td><td style="text-align:left;">256K</td><td style="text-align:left;"><a href="https://huggingface.co/google/gemma-4-26B-A4B" target="_blank" rel="noreferrer">base</a> / <a href="https://huggingface.co/google/gemma-4-26B-A4B-it" target="_blank" rel="noreferrer">IT</a></td></tr></tbody></table><p>Among these, <strong>E2B</strong> and <strong>E4B</strong> are small variants suitable for edge deployment, supporting image, video, text, and <strong>audio</strong> inputs; <strong>31B</strong> and <strong>26B A4B</strong> are large variants supporting image, video, and text inputs.</p><p><strong>Arena AI Rankings (as of April 2026)</strong>: The 31B dense model ranks <strong>#3</strong> among open-source models on the Arena AI text leaderboard, and the 26B MoE ranks <strong>#6</strong>, capable of beating models with 20x more parameters. This extreme &quot;intelligence per parameter&quot; means developers can achieve frontier-level capabilities with significantly less hardware.</p><h4 id="large-models-26b-31b" tabindex="-1">Large Models (26B / 31B) <a class="header-anchor" href="#large-models-26b-31b" aria-label="Permalink to &quot;Large Models (26B / 31B)&quot;">​</a></h4><p>Designed for researchers and developers, the unquantized bfloat16 weights run efficiently on a single 80GB NVIDIA H100 GPU; quantized versions can run locally on consumer-grade GPUs, powering IDEs, coding assistants, and agentic workflows. The 26B MoE activates only 3.8B parameters during inference with extremely low latency; the 31B Dense pursues maximum raw quality and is an ideal base for fine-tuning.</p><h4 id="edge-models-e2b-e4b" tabindex="-1">Edge Models (E2B / E4B) <a class="header-anchor" href="#edge-models-e2b-e4b" aria-label="Permalink to &quot;Edge Models (E2B / E4B)&quot;">​</a></h4><p>Designed from the ground up for mobile and IoT devices, activating only 2B / 4B effective parameters during inference to save memory and battery life. Google has deeply collaborated with the Pixel team and mobile hardware manufacturers like Qualcomm and MediaTek, enabling these multimodal models to run <strong>fully offline with near-zero latency</strong> on phones, Raspberry Pi, NVIDIA Jetson Orin Nano, and other edge devices. Android developers can prototype via the AICore Developer Preview with forward compatibility to the upcoming Gemini Nano 4.</p><hr><h3 id="_2-architecture-features" tabindex="-1">2. Architecture Features <a class="header-anchor" href="#_2-architecture-features" aria-label="Permalink to &quot;2. Architecture Features&quot;">​</a></h3><p>Gemma 4 incorporates multiple proven architectural innovations, achieving an excellent balance between compatibility, efficiency, and long-context support:</p><h4 id="_2-1-alternating-attention-mechanism" tabindex="-1">2.1 Alternating Attention Mechanism <a class="header-anchor" href="#_2-1-alternating-attention-mechanism" aria-label="Permalink to &quot;2.1 Alternating Attention Mechanism&quot;">​</a></h4><p>Gemma 4 uses an alternating layer structure of <strong>local sliding window attention</strong> and <strong>global full-context attention</strong>. Smaller dense models use a 512-token sliding window, while larger models use 1024 tokens. This design controls computation while preserving long-range dependency modeling.</p><h4 id="_2-2-dual-rope-configuration" tabindex="-1">2.2 Dual RoPE Configuration <a class="header-anchor" href="#_2-2-dual-rope-configuration" aria-label="Permalink to &quot;2.2 Dual RoPE Configuration&quot;">​</a></h4><p>The model uses two RoPE (Rotary Position Embedding) configurations: standard RoPE for sliding window layers and scaled RoPE for global layers, to better support extra-long contexts.</p><h4 id="_2-3-per-layer-embeddings-ple" tabindex="-1">2.3 Per-Layer Embeddings (PLE) <a class="header-anchor" href="#_2-3-per-layer-embeddings-ple" aria-label="Permalink to &quot;2.3 Per-Layer Embeddings (PLE)&quot;">​</a></h4><p>PLE is one of the most distinctive innovations in Gemma 4&#39;s small models (first introduced in Gemma-3n). In traditional Transformers, each token gets only one embedding vector at input, and all subsequent layers build on it. PLE adds a parallel, low-dimensional conditioning path alongside the main residual stream — generating a dedicated small vector for each token at each layer, combining token identity information and contextual information. This allows each layer to receive token-specific information without needing to pack everything into the initial embedding. Since PLE dimensions are much smaller than the main hidden dimension, the parameter cost is low, but it brings significant per-layer specialization effects.</p><h4 id="_2-4-shared-kv-cache" tabindex="-1">2.4 Shared KV Cache <a class="header-anchor" href="#_2-4-shared-kv-cache" aria-label="Permalink to &quot;2.4 Shared KV Cache&quot;">​</a></h4><p>The last several layers of the model no longer independently compute their own Key and Value projections, but instead <strong>reuse</strong> the KV tensors from the last non-shared layer of the same attention type (sliding or global). This optimization significantly reduces memory usage and computation during long-text inference with minimal quality impact, making it ideal for edge deployment.</p><h4 id="_2-5-vision-encoder" tabindex="-1">2.5 Vision Encoder <a class="header-anchor" href="#_2-5-vision-encoder" aria-label="Permalink to &quot;2.5 Vision Encoder&quot;">​</a></h4><p>The vision encoder uses learned 2D positional encoding and multi-dimensional RoPE, supports <strong>variable aspect ratio</strong> inputs, and can be configured with different image token counts (70, 140, 280, 560, 1120), flexibly trading off between speed, memory, and quality.</p><h4 id="_2-6-audio-encoder" tabindex="-1">2.6 Audio Encoder <a class="header-anchor" href="#_2-6-audio-encoder" aria-label="Permalink to &quot;2.6 Audio Encoder&quot;">​</a></h4><p>The small variants (E2B, E4B) include a built-in USM-style Conformer audio encoder, using the same base architecture as Gemma-3n, supporting speech understanding and transcription tasks.</p><hr><h3 id="_3-core-capabilities" tabindex="-1">3. Core Capabilities <a class="header-anchor" href="#_3-core-capabilities" aria-label="Permalink to &quot;3. Core Capabilities&quot;">​</a></h3><p>Gemma 4 goes beyond simple chat scenarios, demonstrating strong capabilities across multiple dimensions:</p><h4 id="_3-1-advanced-reasoning" tabindex="-1">3.1 Advanced Reasoning <a class="header-anchor" href="#_3-1-advanced-reasoning" aria-label="Permalink to &quot;3.1 Advanced Reasoning&quot;">​</a></h4><p>Capable of multi-step planning and deep logical reasoning, with significant improvements on math and instruction-following benchmarks.</p><h4 id="_3-2-agentic-workflows" tabindex="-1">3.2 Agentic Workflows <a class="header-anchor" href="#_3-2-agentic-workflows" aria-label="Permalink to &quot;3.2 Agentic Workflows&quot;">​</a></h4><p>Natively supports <strong>Function Calling</strong>, <strong>structured JSON output</strong>, and <strong>system instructions</strong>, enabling the construction of autonomous agents that interact with external tools and APIs to reliably execute complex workflows.</p><h4 id="_3-3-code-generation" tabindex="-1">3.3 Code Generation <a class="header-anchor" href="#_3-3-code-generation" aria-label="Permalink to &quot;3.3 Code Generation&quot;">​</a></h4><p>Supports high-quality offline code generation, turning workstations into local-first AI coding assistants.</p><h4 id="_3-4-vision-and-audio" tabindex="-1">3.4 Vision and Audio <a class="header-anchor" href="#_3-4-vision-and-audio" aria-label="Permalink to &quot;3.4 Vision and Audio&quot;">​</a></h4><p>All models natively process video and images with variable resolution support, excelling at OCR, chart understanding, and other visual tasks. E2B and E4B additionally support native audio input for speech recognition and understanding.</p><h4 id="_3-5-long-context" tabindex="-1">3.5 Long Context <a class="header-anchor" href="#_3-5-long-context" aria-label="Permalink to &quot;3.5 Long Context&quot;">​</a></h4><p>Edge models support <strong>128K</strong> context windows, and large models up to <strong>256K</strong>, allowing complete code repositories or long documents to be passed in a single prompt.</p><h4 id="_3-6-multilingual-support" tabindex="-1">3.6 Multilingual Support <a class="header-anchor" href="#_3-6-multilingual-support" aria-label="Permalink to &quot;3.6 Multilingual Support&quot;">​</a></h4><p>Natively trained on <strong>140+ languages</strong>, helping developers build high-performance applications for global users.</p><h4 id="_3-7-multimodal-task-demonstrations" tabindex="-1">3.7 Multimodal Task Demonstrations <a class="header-anchor" href="#_3-7-multimodal-task-demonstrations" aria-label="Permalink to &quot;3.7 Multimodal Task Demonstrations&quot;">​</a></h4><p>In Hugging Face&#39;s practical testing, Gemma 4 demonstrated out-of-the-box capabilities in the following multimodal scenarios:</p><ul><li><strong>Object Detection and Localization</strong>: The model can natively return detected bounding box coordinates in JSON format without specific instructions or constrained generation.</li><li><strong>GUI Element Detection</strong>: Can identify and locate UI elements (such as buttons, menu items, etc.), suitable for GUI automation scenarios.</li><li><strong>Image Captioning</strong>: All model sizes excel at capturing details in complex scenes.</li><li><strong>Video Understanding</strong>: Although not explicitly post-trained on video, the model can understand video content with or without audio. Small variants can process both video frames and audio simultaneously.</li><li><strong>Audio QA and Transcription</strong>: E2B and E4B support description and transcription of speech content, with training data primarily focused on speech.</li><li><strong>Multimodal Reasoning (Thinking)</strong>: Supports chain-of-thought reasoning mode on multimodal inputs.</li><li><strong>Multimodal Function Calling</strong>: Can recognize information from image content and call external tools, e.g., identifying a location in an image and then calling a weather query API.</li></ul><hr><h3 id="_4-benchmark-results" tabindex="-1">4. Benchmark Results <a class="header-anchor" href="#_4-benchmark-results" aria-label="Permalink to &quot;4. Benchmark Results&quot;">​</a></h3><p>Gemma 4 achieves excellent results across multiple dimensions including reasoning, coding, vision, audio, and long context. The 31B dense model achieves an LMArena score (text-only) of <strong>1452</strong>, while the 26B MoE achieves <strong>1441</strong> with only 4B active parameters.</p><p>Below are the main benchmark results for the instruction-tuned versions:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Benchmark</th><th style="text-align:center;">Gemma 4 31B</th><th style="text-align:center;">Gemma 4 26B A4B</th><th style="text-align:center;">Gemma 4 E4B</th><th style="text-align:center;">Gemma 4 E2B</th><th style="text-align:center;">Gemma 3 27B</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Reasoning &amp; Knowledge</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:left;">MMLU Pro</td><td style="text-align:center;">85.2%</td><td style="text-align:center;">82.6%</td><td style="text-align:center;">69.4%</td><td style="text-align:center;">60.0%</td><td style="text-align:center;">67.6%</td></tr><tr><td style="text-align:left;">AIME 2026 (no tools)</td><td style="text-align:center;">89.2%</td><td style="text-align:center;">88.3%</td><td style="text-align:center;">42.5%</td><td style="text-align:center;">37.5%</td><td style="text-align:center;">20.8%</td></tr><tr><td style="text-align:left;">GPQA Diamond</td><td style="text-align:center;">84.3%</td><td style="text-align:center;">82.3%</td><td style="text-align:center;">58.6%</td><td style="text-align:center;">43.4%</td><td style="text-align:center;">42.4%</td></tr><tr><td style="text-align:left;">BigBench Extra Hard</td><td style="text-align:center;">74.4%</td><td style="text-align:center;">64.8%</td><td style="text-align:center;">33.1%</td><td style="text-align:center;">21.9%</td><td style="text-align:center;">19.3%</td></tr><tr><td style="text-align:left;"><strong>Coding</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:left;">LiveCodeBench v6</td><td style="text-align:center;">80.0%</td><td style="text-align:center;">77.1%</td><td style="text-align:center;">52.0%</td><td style="text-align:center;">44.0%</td><td style="text-align:center;">29.1%</td></tr><tr><td style="text-align:left;">Codeforces ELO</td><td style="text-align:center;">2150</td><td style="text-align:center;">1718</td><td style="text-align:center;">940</td><td style="text-align:center;">633</td><td style="text-align:center;">110</td></tr><tr><td style="text-align:left;"><strong>Vision</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:left;">MMMU Pro</td><td style="text-align:center;">76.9%</td><td style="text-align:center;">73.8%</td><td style="text-align:center;">52.6%</td><td style="text-align:center;">44.2%</td><td style="text-align:center;">49.7%</td></tr><tr><td style="text-align:left;">MATH-Vision</td><td style="text-align:center;">85.6%</td><td style="text-align:center;">82.4%</td><td style="text-align:center;">59.5%</td><td style="text-align:center;">52.4%</td><td style="text-align:center;">46.0%</td></tr><tr><td style="text-align:left;"><strong>Long Context</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:left;">MRCR v2 128K (avg)</td><td style="text-align:center;">66.4%</td><td style="text-align:center;">44.1%</td><td style="text-align:center;">25.4%</td><td style="text-align:center;">19.1%</td><td style="text-align:center;">13.5%</td></tr></tbody></table><p><strong>Key Highlights:</strong></p><ul><li><strong>26B A4B (MoE)</strong> activates only 4B parameters, achieving performance close to the 31B dense model, with extremely high efficiency.</li><li>Compared to the previous generation Gemma 3 27B, Gemma 4 improves AIME 2026 math reasoning by over <strong>4x</strong> (20.8% → 89.2%), and Codeforces coding score by over <strong>15x</strong> (110 → 1718+).</li><li>Vision and long context capabilities significantly surpass the previous generation.</li></ul><hr><h3 id="_5-ecosystem-and-inference-framework-support" tabindex="-1">5. Ecosystem and Inference Framework Support <a class="header-anchor" href="#_5-ecosystem-and-inference-framework-support" aria-label="Permalink to &quot;5. Ecosystem and Inference Framework Support&quot;">​</a></h3><p>Gemma 4 has broad toolchain and platform support, allowing developers to choose flexibly based on their needs:</p><h4 id="_5-1-inference-frameworks-day-one-support" tabindex="-1">5.1 Inference Frameworks (Day-One Support) <a class="header-anchor" href="#_5-1-inference-frameworks-day-one-support" aria-label="Permalink to &quot;5.1 Inference Frameworks (Day-One Support)&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">Framework</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>transformers</strong></td><td style="text-align:left;">Official integration, supports <code>AutoModelForMultimodalLM</code>, <code>any-to-any</code> pipeline</td></tr><tr><td style="text-align:left;"><strong>llama.cpp</strong></td><td style="text-align:left;">Supports text+image inference, available via OpenAI-compatible API, compatible with LM Studio, Jan, and other local apps</td></tr><tr><td style="text-align:left;"><strong>vLLM</strong></td><td style="text-align:left;">High-performance inference engine</td></tr><tr><td style="text-align:left;"><strong>SGLang</strong></td><td style="text-align:left;">High-performance inference engine, transformers backend</td></tr><tr><td style="text-align:left;"><strong>MLX</strong></td><td style="text-align:left;">Native Apple Silicon support with TurboQuant quantization optimization</td></tr><tr><td style="text-align:left;"><strong>Ollama</strong></td><td style="text-align:left;">One-click local deployment</td></tr><tr><td style="text-align:left;"><strong>LM Studio</strong></td><td style="text-align:left;">GUI-based local inference</td></tr><tr><td style="text-align:left;"><strong>transformers.js</strong></td><td style="text-align:left;">Browser-based execution (WebGPU)</td></tr><tr><td style="text-align:left;"><strong>mistral.rs</strong></td><td style="text-align:left;">Rust-native inference engine, supports all modalities and built-in tool calling</td></tr><tr><td style="text-align:left;"><strong>ONNX</strong></td><td style="text-align:left;">Provides ONNX format checkpoints for edge device and browser deployment</td></tr><tr><td style="text-align:left;"><strong>LiteRT-LM</strong></td><td style="text-align:left;">Google&#39;s edge inference runtime</td></tr><tr><td style="text-align:left;"><strong>NVIDIA NIM / NeMo</strong></td><td style="text-align:left;">NVIDIA inference and training platform</td></tr></tbody></table><h4 id="_5-2-hardware-platforms" tabindex="-1">5.2 Hardware Platforms <a class="header-anchor" href="#_5-2-hardware-platforms" aria-label="Permalink to &quot;5.2 Hardware Platforms&quot;">​</a></h4><p>Gemma 4 is optimized for multiple hardware platforms:</p><ul><li><strong>NVIDIA GPU</strong>: Full coverage from Jetson Orin Nano to Blackwell series</li><li><strong>AMD GPU</strong>: Integration through the open-source <strong>ROCm</strong> software stack</li><li><strong>Google TPU</strong>: Supports Trillium and Ironwood TPU for large-scale deployment</li><li><strong>Apple Silicon</strong>: Native support via MLX</li><li><strong>Mobile Chips</strong>: Optimized in collaboration with Qualcomm and MediaTek</li></ul><h4 id="_5-3-development-platforms-and-quick-start" tabindex="-1">5.3 Development Platforms and Quick Start <a class="header-anchor" href="#_5-3-development-platforms-and-quick-start" aria-label="Permalink to &quot;5.3 Development Platforms and Quick Start&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">Platform</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="https://aistudio.google.com/" target="_blank" rel="noreferrer">Google AI Studio</a></td><td style="text-align:left;">Try 31B and 26B MoE online</td></tr><tr><td style="text-align:left;"><a href="https://ai.google.dev/edge" target="_blank" rel="noreferrer">Google AI Edge Gallery</a></td><td style="text-align:left;">Try edge models E4B and E2B</td></tr><tr><td style="text-align:left;"><a href="https://developer.android.com/studio" target="_blank" rel="noreferrer">Android Studio Agent Mode</a></td><td style="text-align:left;">Android app development integration</td></tr><tr><td style="text-align:left;"><a href="https://huggingface.co/collections/google/gemma-4" target="_blank" rel="noreferrer">Hugging Face</a></td><td style="text-align:left;">Model downloads and community</td></tr><tr><td style="text-align:left;"><a href="https://www.kaggle.com/" target="_blank" rel="noreferrer">Kaggle</a></td><td style="text-align:left;">Model downloads and Gemma 4 Good Challenge</td></tr><tr><td style="text-align:left;"><a href="https://colab.research.google.com/" target="_blank" rel="noreferrer">Google Colab</a></td><td style="text-align:left;">Free fine-tuning and experimentation</td></tr><tr><td style="text-align:left;"><a href="https://cloud.google.com/vertex-ai" target="_blank" rel="noreferrer">Vertex AI</a></td><td style="text-align:left;">Enterprise deployment (Cloud Run / GKE / TPU acceleration)</td></tr></tbody></table><hr><h3 id="_6-fine-tuning-support" tabindex="-1">6. Fine-tuning Support <a class="header-anchor" href="#_6-fine-tuning-support" aria-label="Permalink to &quot;6. Fine-tuning Support&quot;">​</a></h3><p>Gemma 4&#39;s highly optimized architecture enables efficient fine-tuning across various hardware — from billions of Android devices to laptop GPUs, developer workstations, and accelerators. The community already has successful fine-tuning examples: INSAIT created BgGPT, a Bulgarian-first language model based on Gemma, and Yale University leveraged Cell2Sentence-Scale to discover new cancer treatment pathways.</p><p>Gemma 4 supports fine-tuning with various tools:</p><ul><li><strong>TRL (Transformer Reinforcement Learning)</strong>: Supports multimodal tool-response training, can receive image feedback from environments (e.g., training Gemma 4 to learn driving in the CARLA simulator).</li><li><strong>TRL on Vertex AI</strong>: Provides complete examples for SFT fine-tuning on Google Cloud Vertex AI, with the ability to freeze vision and audio towers for function calling capability extension.</li><li><strong>Unsloth Studio</strong>: Supports fine-tuning via GUI locally or on Colab.</li><li><strong>Keras</strong>: Google&#39;s high-level deep learning API support.</li></ul><hr><h3 id="_7-license-and-safety" tabindex="-1">7. License and Safety <a class="header-anchor" href="#_7-license-and-safety" aria-label="Permalink to &quot;7. License and Safety&quot;">​</a></h3><p>Gemma 4 is released under the <strong>Apache 2.0</strong> open-source license, granting developers complete flexibility and digital sovereignty — full control over data, infrastructure, and models, with the freedom to build and deploy in any environment, locally or in the cloud.</p><p>In terms of safety, Gemma 4 undergoes the same rigorous infrastructure security protocols as Google&#39;s proprietary models, providing a trustworthy and transparent foundation for enterprises and sovereign organizations.</p><hr><h3 id="_8-summary" tabindex="-1">8. Summary <a class="header-anchor" href="#_8-summary" aria-label="Permalink to &quot;8. Summary&quot;">​</a></h3><p>Gemma 4 is among the best open-source multimodal models available today. Its core advantages include:</p><ol><li><strong>Truly Open Source</strong>: Apache 2.0 license, free for commercial use, with full control.</li><li><strong>Extreme Parameter Efficiency</strong>: Beats models with 20x more parameters, Arena AI open-source ranking Top 3/6.</li><li><strong>Full Modality Support</strong>: Unified processing of text, image, video, and audio, covering 140+ languages.</li><li><strong>Full Size Coverage</strong>: From 2.3B edge models (mobile/IoT) to 31B server-grade models, fitting all scenarios.</li><li><strong>Efficient Architecture</strong>: PLE, shared KV cache, MoE, and other designs maintain high performance while significantly reducing resource requirements.</li><li><strong>Agent-Ready</strong>: Native function calling, structured output, and system instructions, suitable for building complex agentic workflows.</li><li><strong>Complete Ecosystem</strong>: Day-one support from mainstream inference frameworks, multi-hardware platform optimization (NVIDIA / AMD ROCm / Google TPU / Apple Silicon), with quantization and fine-tuning tools readily available.</li></ol><blockquote><p>For more information, see:</p><ul><li><a href="https://huggingface.co/blog/gemma4" target="_blank" rel="noreferrer">Hugging Face Blog - Welcome Gemma 4</a></li><li><a href="https://blog.google/innovation-and-ai/technology/developers-tools/gemma-4/" target="_blank" rel="noreferrer">Google Blog - Gemma 4</a></li><li><a href="https://huggingface.co/collections/google/gemma-4" target="_blank" rel="noreferrer">Hugging Face Gemma 4 Model Collection</a></li></ul></blockquote>',78)])])}const u=t(r,[["render",i]]);export{h as __pageData,u as default};
